{"title":"Shot Map (Vega-Lite)","type":"vega","aggs":[],"params":{"spec":"{
  $schema: https://vega.github.io/schema/vega-lite/v5.json
  data: {
    url: {
      %context%: true
      index: football_events
      body: {
        size: 5000
        _source: [location_x, location_y, shot_xg, shot_outcome, player_name, team_name, minute]
        query: {bool: {must: [{match: {type_name: "Shot"}}]}}
      }
    }
    format: {property: "hits.hits"}
  }
  layer: [
    {
      mark: {type: rect, color: "#2d5a27", opacity: 1}
      encoding: {
        x: {value: 0}
        y: {value: 0}
        x2: {value: 780}
        y2: {value: 520}
      }
    }
    {
      mark: {type: rect, color: "#3a7a34", opacity: 1}
      encoding: {
        x: {value: 390}
        y: {value: 130}
        x2: {value: 780}
        y2: {value: 390}
      }
    }
    {
      mark: {type: circle, opacity: 0.75, stroke: white, strokeWidth: 1}
      encoding: {
        x: {field: _source.location_x, type: quantitative, scale: {domain: [0, 120], range: [0, 780]}, axis: {title: null, labels: false, ticks: false}}
        y: {field: _source.location_y, type: quantitative, scale: {domain: [80, 0], range: [0, 520]}, axis: {title: null, labels: false, ticks: false}}
        color: {
          field: _source.shot_outcome
          type: nominal
          scale: {domain: ["Goal", "Saved", "Blocked", "Off T", "Wayward", "Post"]
                  range: ["#ff4444", "#ffaa00", "#4499ff", "#aaaaaa", "#888888", "#ffff00"]}
          legend: {title: "Outcome"}
        }
        size: {
          field: _source.shot_xg
          type: quantitative
          scale: {range: [30, 400]}
          legend: {title: "xG"}
        }
        tooltip: [
          {field: _source.player_name, title: "Player"}
          {field: _source.team_name, title: "Team"}
          {field: _source.shot_outcome, title: "Outcome"}
          {field: _source.shot_xg, title: "xG", format: ".3f"}
          {field: _source.minute, title: "Minute"}
        ]
      }
    }
  ]
  width: 780
  height: 520
  config: {background: "#1a1a2e", view: {stroke: null}}
}"}}

{"title":"xG Trend by Minute (Vega-Lite)","type":"vega","aggs":[],"params":{"spec":"{
  $schema: https://vega.github.io/schema/vega-lite/v5.json
  data: {
    url: {
      %context%: true
      index: football_events
      body: {
        size: 0
        query: {bool: {must: [{match: {type_name: "Shot"}}]}}
        aggs: {
          by_minute: {
            histogram: {field: "minute", interval: 5}
            aggs: {
              by_team: {
                terms: {field: "team_name", size: 2}
                aggs: {total_xg: {sum: {field: "shot_xg"}}}
              }
            }
          }
        }
      }
    }
    format: {property: "aggregations.by_minute.buckets"}
  }
  transform: [
    {flatten: ["by_team.buckets"], as: ["team_bucket"]}
    {calculate: "datum.key", as: "minute"}
    {calculate: "datum.team_bucket.key", as: "team"}
    {calculate: "datum.team_bucket.total_xg.value", as: "xg"}
  ]
  mark: {type: area, opacity: 0.6, line: true}
  encoding: {
    x: {field: minute, type: quantitative, title: "Match Minute (5-min bins)"}
    y: {field: xg, type: quantitative, title: "Expected Goals (xG)", stack: null}
    color: {field: team, type: nominal, title: "Team"}
    tooltip: [
      {field: minute, title: "Minute"}
      {field: team, title: "Team"}
      {field: xg, title: "xG", format: ".3f"}
    ]
  }
  width: 600
  height: 300
}"}}

{"title":"Pass Network (Vega-Lite)","type":"vega","aggs":[],"params":{"spec":"{
  $schema: https://vega.github.io/schema/vega-lite/v5.json
  data: {
    url: {
      %context%: true
      index: football_events
      body: {
        size: 0
        query: {bool: {must: [{match: {type_name: "Pass"}}, {exists: {field: "pass_outcome"}}]}}
        aggs: {
          by_team: {
            terms: {field: "team_name", size: 2}
            aggs: {
              by_zone_x: {histogram: {field: "location_x", interval: 40}
                aggs: {by_zone_y: {histogram: {field: "location_y", interval: 26.67}
                  aggs: {
                    pass_count: {value_count: {field: "event_id"}}
                    avg_xg:     {avg: {field: "shot_xg"}}
                  }}}}
            }
          }
        }
      }
    }
    format: {property: "aggregations.by_team.buckets"}
  }
  transform: [
    {flatten: ["by_zone_x.buckets"], as: ["xb"]}
    {flatten: ["xb.by_zone_y.buckets"], as: ["yb"]}
    {calculate: "datum.key", as: "team"}
    {calculate: "datum.xb.key + 20", as: "cx"}
    {calculate: "datum.yb.key + 13", as: "cy"}
    {calculate: "datum.yb.pass_count.value", as: "passes"}
  ]
  mark: {type: circle}
  encoding: {
    x: {field: cx, type: quantitative, scale: {domain: [0, 120]}, title: "Pitch X"}
    y: {field: cy, type: quantitative, scale: {domain: [80, 0]}, title: "Pitch Y"}
    size: {field: passes, type: quantitative, title: "Pass Count", scale: {range: [50, 2000]}}
    color: {field: team, type: nominal, title: "Team"}
    opacity: {value: 0.7}
    tooltip: [
      {field: team, title: "Team"}
      {field: cx, title: "Zone X"}
      {field: cy, title: "Zone Y"}
      {field: passes, title: "Passes"}
    ]
  }
  width: 600
  height: 400
  config: {background: "#2d5a27"}
}"}}
